#!/usr/bin/env node
const fs = require('fs');
const path = require('path');
const { randomBytes } = require('crypto');
const { hashPasswordForStorage } = require('../src/application/usecases/AuthUseCases');

function hashPassword(password, pepper) {
  return hashPasswordForStorage(password, pepper);
}

function randomSecret(length = 24) {
  return randomBytes(length).toString('base64url');
}

function ensureDir(target) {
  fs.mkdirSync(target, { recursive: true });
}

function writeFileSafe(filePath, content) {
  fs.writeFileSync(filePath, content, { encoding: 'utf8', mode: 0o600 });
}

function main() {
  const root = path.resolve(__dirname, '..');
  const configDir = path.join(root, 'config');
  const secretsDir = path.join(root, '.secrets');
  const usersFile = path.join(configDir, 'admin-users.production.json');
  const envFile = path.join(root, '.env.production.local');
  const passwordFile = path.join(secretsDir, 'admin-initial-passwords.txt');

  ensureDir(configDir);
  ensureDir(secretsDir);

  const pepper = randomSecret(24);
  const users = [
    { id: 'u-root-1', username: 'root_owner', displayName: '平台管理员', role: 'super_admin' },
    { id: 'u-ops-1', username: 'ops_lead', displayName: '运营负责人', role: 'ops_admin' },
    { id: 'u-audit-1', username: 'audit_lead', displayName: '审计员', role: 'auditor' },
    { id: 'u-skill-1', username: 'skill_owner', displayName: '技能管理员', role: 'skill_admin' }
  ];

  const plainPasswords = users.map((u) => ({
    username: u.username,
    password: randomSecret(18)
  }));
  const passwordByUser = new Map(plainPasswords.map((x) => [x.username, x.password]));
  const productionUsers = users.map((u) => ({
    ...u,
    passwordHash: hashPassword(passwordByUser.get(u.username), pepper)
  }));

  writeFileSafe(usersFile, `${JSON.stringify(productionUsers, null, 2)}\n`);

  const envContent = [
    '# Generated by scripts/bootstrap-production-auth.js',
    'NODE_ENV=production',
    'DB_DRIVER=sqlite',
    'SQLITE_PATH=./data/dcf.sqlite',
    'HOST=127.0.0.1',
    'PORT=8092',
    `AUTH_USERS_FILE=${usersFile}`,
    `AUTH_PASSWORD_PEPPER=${pepper}`,
    'AUTH_REQUIRE_EXTERNAL_USERS=1',
    'AUTH_FORBID_DEMO_USERS=1',
    'AUTH_SESSION_SLIDING=1',
    'AUTH_SINGLE_SESSION_PER_USER=1',
    'AUTH_MAX_FAILED_ATTEMPTS=5',
    'AUTH_LOCKOUT_MS=900000',
    'AUTH_FAIL_WINDOW_MS=600000',
    'CORS_ALLOW_ORIGIN=https://admin.example.com'
  ].join('\n');
  writeFileSafe(envFile, `${envContent}\n`);

  const passwordLines = [
    '# Initial admin passwords (rotate after first login)',
    `generatedAt=${new Date().toISOString()}`,
    ...plainPasswords.map((item) => `${item.username}=${item.password}`)
  ].join('\n');
  writeFileSafe(passwordFile, `${passwordLines}\n`);

  console.log(JSON.stringify({
    ok: true,
    usersFile,
    envFile,
    passwordFile,
    next: [
      '1) source .env.production.local',
      '2) npm run verify:release',
      '3) npm start',
      '4) 登录后立即重置初始密码并删除 .secrets/admin-initial-passwords.txt'
    ]
  }, null, 2));
}

main();
